t.script:
function shareRegulation() {
    if (navigator.share) {
        navigator.share({
            title: document.title,
            text: 'Lihat peraturan ini',
            url: window.location.href
        });
    } else {
        navigator.clipboard.writeText(window.location.href).then(function() {
            alert('URL berhasil disalin ke clipboard!');
        });
    }
}

// Font size adjustment
let currentFontSize = 16;
function adjustFontSize(delta) {
    currentFontSize = Math.max(12, Math.min(24, currentFontSize + delta));
    document.querySelectorAll('.regulation-content-main').forEach(el => {
        el.style.fontSize = currentFontSize + 'px';
    });
}

// Fullscreen toggle
function toggleFullscreen() {
    const content = document.querySelector('.regulation-content-main');
    if (content.style.maxHeight !== 'none') {
        content.style.maxHeight = 'none';
        content.style.position = 'fixed';
        content.style.top = '0';
        content.style.left = '0';
        content.style.right = '0';
        content.style.bottom = '0';
        content.style.zIndex = '9999';
        content.style.background = 'white';
        content.style.padding = '40px';
    } else {
        content.style.maxHeight = 'calc(100vh - 250px)';
        content.style.position = '';
        content.style.top = '';
        content.style.left = '';
        content.style.right = '';
        content.style.bottom = '';
        content.style.zIndex = '';
        content.style.padding = '';
    }
}

// Store TOC elements globally
window.tocElements = {};

// Toggle collapse for BAB items (only toggle, no scroll)
window.toggleBab = function(babId, evt) {
    if (evt) {
        evt.preventDefault();
        evt.stopPropagation();
    }
    const subItems = document.getElementById('sub-' + babId);
    const icon = document.getElementById('icon-' + babId);
    if (subItems) {
        if (subItems.style.display === 'none') {
            subItems.style.display = 'block';
            if (icon) icon.className = 'fa fa-chevron-down fa-fw';
        } else {
            subItems.style.display = 'none';
            if (icon) icon.className = 'fa fa-chevron-right fa-fw';
        }
    }
    return false;
};

// Scroll to TOC element AND expand if it's a BAB
window.scrollToTocElement = function(key, evt) {
    if (evt) {
        evt.preventDefault();
        evt.stopPropagation();
    }

    // If clicking a BAB, also expand it
    if (key.startsWith('BAB-')) {
        const subItems = document.getElementById('sub-' + key);
        const icon = document.getElementById('icon-' + key);
        if (subItems && subItems.style.display === 'none') {
            subItems.style.display = 'block';
            if (icon) icon.className = 'fa fa-chevron-down fa-fw';
        }
    }

    const element = window.tocElements[key];
    const scrollContainer = document.querySelector('.regulation-content-main');

    if (element && scrollContainer) {
        const containerRect = scrollContainer.getBoundingClientRect();
        const elementRect = element.getBoundingClientRect();
        const scrollTop = scrollContainer.scrollTop + (elementRect.top - containerRect.top) - 30;

        scrollContainer.scrollTo({
            top: scrollTop,
            behavior: 'smooth'
        });

        // Update active state
        document.querySelectorAll('.toc-item, .toc-sub-item').forEach(l => l.classList.remove('active'));
        if (evt && evt.target) {
            const targetEl = evt.target.closest('a, span');
            if (targetEl) targetEl.classList.add('active');
        }
    }
    return false;
};

// Generate dynamic TOC from content
document.addEventListener('DOMContentLoaded', function() {
    const scrollContainer = document.querySelector('.regulation-content-main');
    const tocNav = document.getElementById('toc-nav');
    const tocBabContainer = document.getElementById('toc-bab-container');

    if (!scrollContainer || !tocBabContainer) return;

    // Find all BAB and Pasal in content
    const contentText = scrollContainer.innerHTML;
    const allElements = scrollContainer.querySelectorAll('*');

    // Structure to hold BAB -> Pasal mapping
    const structure = {};
    let currentBab = null;

    // Regex patterns
    const babPattern = /^BAB\s+([IVXLCDM]+|[0-9]+)/i;
    const pasalPattern = /^Pasal\s+(\d+[A-Z]?)/i;

    allElements.forEach(el => {
        const text = el.textContent.trim();
        const directText = Array.from(el.childNodes)
            .filter(node => node.nodeType === 3)
            .map(node => node.textContent.trim())
            .join(' ').trim();

        // Check for BAB
        const babMatch = directText.match(babPattern) || text.substring(0, 20).match(babPattern);
        if (babMatch && !el.closest('.toc-item')) {
            const babNum = babMatch[1];
            const babKey = 'BAB-' + babNum;
            if (!structure[babKey]) {
                structure[babKey] = {
                    element: el,
                    title: 'BAB ' + babNum,
                    pasals: []
                };
                currentBab = babKey;
                window.tocElements[babKey] = el;
            }
        }

        // Check for Pasal
        const pasalMatch = directText.match(pasalPattern) || text.substring(0, 15).match(pasalPattern);
        if (pasalMatch && currentBab && !el.closest('.toc-item')) {
            const pasalNum = pasalMatch[1];
            const pasalKey = currentBab + '-Pasal-' + pasalNum;
            // Avoid duplicates
            if (!structure[currentBab].pasals.find(p => p.key === pasalKey)) {
                structure[currentBab].pasals.push({
                    key: pasalKey,
                    element: el,
                    title: 'Pasal ' + pasalNum
                });
                window.tocElements[pasalKey] = el;
            }
        }
    });

    // Generate TOC HTML
    let tocHtml = '';
    Object.keys(structure).forEach(babKey => {
        const bab = structure[babKey];
        const hasPasals = bab.pasals.length > 0;

        tocHtml += '<div class="toc-bab-item">';
        tocHtml += '<a class="nav-link small py-1 px-2 toc-item d-flex align-items-center" href="javascript:void(0)" ';
        tocHtml += "onclick=\"scrollToTocElement('" + babKey + "', event); return false;\">";

        if (hasPasals) {
            tocHtml += "<span class=\"me-1\" style=\"cursor:pointer\" onclick=\"toggleBab('" + babKey + "', event); return false;\">";
            tocHtml += '<i id="icon-' + babKey + '" class="fa fa-chevron-right fa-fw"></i>';
            tocHtml += '</span>';
        } else {
            tocHtml += '<i class="fa fa-bookmark-o fa-fw me-1"></i>';
        }

        tocHtml += bab.title + '</a>';

        // Sub-items (Pasals)
        if (hasPasals) {
            tocHtml += '<div id="sub-' + babKey + '" class="toc-sub-items ps-3" style="display:none;">';
            bab.pasals.forEach(pasal => {
                tocHtml += '<span class="nav-link small py-0 px-2 toc-sub-item" style="cursor:pointer; font-size: 0.75rem;" ';
                tocHtml += "onclick=\"scrollToTocElement('" + pasal.key + "', event); return false;\">";
                tocHtml += '<i class="fa fa-angle-right fa-fw"></i> ' + pasal.title + '</span>';
            });
            tocHtml += '</div>';
        }

        tocHtml += '</div>';
    });

    tocBabContainer.innerHTML = tocHtml;

    // Handle clicks on static TOC items (Pembukaan, Penjelasan)
    tocNav.addEventListener('click', function(e) {
        const link = e.target.closest('a.toc-item[data-search]');
        if (link) {
            e.preventDefault();
            const searchTerms = link.getAttribute('data-search');
            if (searchTerms) {
                const terms = searchTerms.split(',').map(t => t.trim());

                for (let el of allElements) {
                    const text = el.textContent.trim().toUpperCase();
                    for (let term of terms) {
                        if (text.startsWith(term.toUpperCase()) || text.includes(term.toUpperCase())) {
                            const containerRect = scrollContainer.getBoundingClientRect();
                            const elementRect = el.getBoundingClientRect();
                            const scrollTop = scrollContainer.scrollTop + (elementRect.top - containerRect.top) - 30;

                            scrollContainer.scrollTo({
                                top: scrollTop,
                                behavior: 'smooth'
                            });

                            document.querySelectorAll('.toc-item, .toc-sub-item').forEach(l => l.classList.remove('active'));
                            link.classList.add('active');
                            return;
                        }
                    }
                }
            }
        }
    });
});

document.addEventListener('DOMContentLoaded', function() {
    var content = document.querySelector('.regulation-content-main');
    if (!content) return;

    var dlC = 0;

    // Generate unique slug ID from text
    function dlId(text) {
        dlC++;
        var s = text.substring(0, 50).toLowerCase()
            .replace(/[^a-z0-9\s]/g, '').trim().replace(/\s+/g, '-');
        return 's' + dlC + (s ? '-' + s : '');
    }

    // Show toast notification
    function dlToast(msg) {
        var t = document.createElement('div');
        t.className = 'dl-toast';
        t.textContent = msg;
        document.body.appendChild(t);
        setTimeout(function() { if (t.parentNode) t.remove(); }, 3200);
    }

    // Copy link to clipboard
    function dlCopy(elId) {
        var url = window.location.origin + window.location.pathname + '#' + elId;
        if (navigator.clipboard && navigator.clipboard.writeText) {
            navigator.clipboard.writeText(url).then(function() {
                dlToast('✓ Link berhasil disalin!');
            });
        } else {
            var ta = document.createElement('textarea');
            ta.value = url;
            ta.style.position = 'fixed';
            ta.style.left = '-9999px';
            document.body.appendChild(ta);
            ta.select();
            document.execCommand('copy');
            document.body.removeChild(ta);
            dlToast('✓ Link berhasil disalin!');
        }
    }

    // Add link button to element
    function dlBtn(el) {
        var b = document.createElement('button');
        b.className = 'dl-link-btn';
        b.innerHTML = '';
        b.title = 'Salin link ke bagian ini';
        var id = el.id;
        b.addEventListener('click', function(e) {
            e.preventDefault();
            e.stopPropagation();
            history.replaceState(null, null, '#' + id);
            dlCopy(id);
        });
        el.insertBefore(b, el.firstChild);
    }

    // Wrap element as linkable block
    function dlWrap(el) {
        if (el.classList.contains('dl-block')) return;
        if (!el.id) el.id = dlId(el.textContent);
        el.classList.add('dl-block');
        el.style.position = 'relative';
        dlBtn(el);
    }

    // Get direct text content (not from children)
    function dlDirect(el) {
        var r = [];
        var ch = el.childNodes;
        for (var i = 0; i < ch.length; i++) {
            if (ch[i].nodeType === 3) r.push(ch[i].textContent.trim());
        }
        return r.join(' ').trim();
    }

    // Get all text nodes from element (recursive)
    function dlTextNodes(el) {
        var res = [];
        var ch = el.childNodes;
        for (var i = 0; i < ch.length; i++) {
            if (ch[i].nodeType === 3 && ch[i].textContent.trim().length > 0) {
                res.push(ch[i]);
            } else if (ch[i].nodeType === 1 && !ch[i].classList.contains('dl-sentence')) {
                var sub = dlTextNodes(ch[i]);
                for (var j = 0; j < sub.length; j++) res.push(sub[j]);
            }
        }
        return res;
    }

    // ── 1. Process headings (h1-h6) ──
    content.querySelectorAll('h1,h2,h3,h4,h5,h6').forEach(function(el) {
        dlWrap(el);
    });

    // ── 2. Process big-text markers ──
    var bigRe = /^(BAB\s|Pasal\s|PEMBUKAAN|PENJELASAN|KETENTUAN|PENUTUP|Bagian\s|Paragraf\s)/i;
    content.querySelectorAll('p,div,span,b,strong,center').forEach(function(el) {
        if (el.classList.contains('dl-block')) return;
        if (el.closest('.dl-block')) return;
        var dt = dlDirect(el);
        if (bigRe.test(dt) && dt.length < 200) {
            dlWrap(el);
        }
    });

    // ── 3. Paragraphs → split by sentence (per titik) ──
    content.querySelectorAll('p').forEach(function(p) {
        if (p.classList.contains('dl-block')) return;
        if (p.closest('table,pre,code,.dl-block')) return;
        var txt = p.textContent.trim();
        if (txt.length < 15) return;
        if (p.querySelector('.dl-block')) return;

        // If has complex children, wrap whole paragraph
        if (p.querySelector('a,img,table,div,ul,ol')) {
            dlWrap(p);
            return;
        }

        // Check if has multiple sentences
        if (txt.indexOf('. ') === -1) {
            dlWrap(p);
            return;
        }

        // Collect text nodes before modifying DOM
        var tns = dlTextNodes(p);

        tns.forEach(function(tn) {
            var text = tn.textContent;
            if (text.indexOf('. ') === -1) return;
            if (text.trim().length < 20) return;

            // Split by ". " keeping period with preceding text
            var rawParts = [];
            var rem = text;
            while (true) {
                var di = rem.indexOf('. ');
                if (di === -1) break;
                rawParts.push(rem.substring(0, di + 1));
                rem = rem.substring(di + 2);
            }
            if (rem.trim()) rawParts.push(rem);
            if (rawParts.length < 2) return;

            // Merge short segments (min 40 chars per sentence)
            var parts = [];
            var buffer = '';
            for (var k = 0; k < rawParts.length; k++) {
                buffer += (buffer ? ' ' : '') + rawParts[k];
                if (buffer.length >= 40 || k === rawParts.length - 1) {
                    parts.push(buffer);
                    buffer = '';
                }
            }
            if (parts.length < 2) {
                // Only 1 merged sentence, wrap whole paragraph
                if (!p.classList.contains('dl-block')) dlWrap(p);
                return;
            }

            // Create sentence spans
            var frag = document.createDocumentFragment();
            parts.forEach(function(part) {
                var trimmed = part.trim();
                if (trimmed.length < 10) {
                    frag.appendChild(document.createTextNode(part + ' '));
                    return;
                }
                var sp = document.createElement('span');
                sp.className = 'dl-sentence';
                sp.id = dlId(trimmed);
                sp.textContent = part + ' ';
                sp.style.position = 'relative';
                sp.style.display = 'inline';
                dlBtn(sp);
                frag.appendChild(sp);
            });

            tn.parentNode.replaceChild(frag, tn);
        });
    });

    // ── 4. Handle URL hash (deep link navigation) ──
    function dlGoHash() {
        var h = window.location.hash.substring(1);
        if (!h) return;
        var tgt = document.getElementById(h);
        if (!tgt) return;

        var sc = document.querySelector('.regulation-content-main');
        if (!sc) return;

        setTimeout(function() {
            var cr = sc.getBoundingClientRect();
            var tr = tgt.getBoundingClientRect();
            sc.scrollTo({
                top: sc.scrollTop + (tr.top - cr.top) - 60,
                behavior: 'smooth'
            });
            tgt.classList.add('dl-highlight');
            setTimeout(function() { tgt.classList.remove('dl-highlight'); }, 5500);
        }, 700);
    }

    dlGoHash();
    window.addEventListener('hashchange', dlGoHash);
});
